import flask
import psycopg2
from flask import request


app = flask.Flask(__name__)
app.config["DEBUG"] = True


@app.route('/api/v1/query', methods=['GET'])
def api_query():
    try:
        conn = psycopg2.connect(
            host="localhost",
            database="postgres",
            user="postgres",
            password="<PASSWORD>"
        )

        cursor = conn.cursor()
        postgreSQL_select_Query = "SELECT * FROM public." + request.args['table'] + " WHERE " + request.args['column'] + " = '" + request.args['value'] + "'"

        cursor.execute(postgreSQL_select_Query)
        print("Selecting rows from mobile table using cursor.fetchall")
        mobileRecords = cursor.fetchall()

        print("Print each row and it's columns values")
        for row in mobileRecords:
            print("Id = ", row[0])
            print("Name = ", row[1])
            print("Age = ", row[2])
            print("Address = ", row[3])
            print("Salary = ", row[4], "\n")

        return "Query executed successfully"

    except (Exception, psycopg2.Error) as error:
        return "Error while connecting to PostgreSQL", error


if __name__ == '__main__':
    app.run()